export function initialize(sentinelElement, dotNetHelper) {
    const observer = new IntersectionObserver(entries => {
        if (entries[0].isIntersecting) {
            dotNetHelper.invokeMethodAsync('OnSentinelVisible');
        }
    }, { rootMargin: '100px' });

    observer.observe(sentinelElement);

    return observer;
}

export function dispose(observer) {
    observer.disconnect();
}

@typeparam TItem
@implements IAsyncDisposable

<div class="infinite-scroll-container">
    @foreach (var item in Items)
    {
        @ChildContent(item)
    }

    @if (HasMore)
    {
        <div @ref="_sentinelRef" class="infinite-scroll-sentinel">
            @if (_isLoading)
            {
                <div class="infinite-scroll-spinner"></div>
            }
        </div>
    }
</div>

using Microsoft.AspNetCore.Components;
using Microsoft.JSInterop;

namespace sv_bc86d26e511948bea035f9127f079ac5.Components;

public partial class InfiniteScrollList<TItem> : IAsyncDisposable
{
    [Inject] private IJSRuntime JS { get; set; } = default!;

    [Parameter, EditorRequired] public IReadOnlyList<TItem> Items { get; set; } = [];
    [Parameter, EditorRequired] public bool HasMore { get; set; }
    [Parameter, EditorRequired] public EventCallback OnLoadMore { get; set; }
    [Parameter, EditorRequired] public RenderFragment<TItem> ChildContent { get; set; } = default!;

    private ElementReference _sentinelRef;
    private IJSObjectReference? _module;
    private IJSObjectReference? _observer;
    private DotNetObjectReference<InfiniteScrollList<TItem>>? _dotNetRef;
    private bool _isLoading;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            _dotNetRef = DotNetObjectReference.Create(this);
            _module = await JS.InvokeAsync<IJSObjectReference>(
                "import", "./js/infinite-scroll.js");
            _observer = await _module.InvokeAsync<IJSObjectReference>(
                "initialize", _sentinelRef, _dotNetRef);
        }
    }

    [JSInvokable]
    public async Task OnSentinelVisible()
    {
        if (_isLoading || !HasMore) return;

        _isLoading = true;
        StateHasChanged();

        await OnLoadMore.InvokeAsync();

        _isLoading = false;
        StateHasChanged();
    }

    public async ValueTask DisposeAsync()
    {
        if (_observer is not null && _module is not null)
        {
            await _module.InvokeVoidAsync("dispose", _observer);
        }
        if (_module is not null)
        {
            await _module.DisposeAsync();
        }
        _dotNetRef?.Dispose();
    }
}

.infinite-scroll-container {
    overflow-y: auto;
    max-height: 80vh;
}

.infinite-scroll-sentinel {
    display: flex;
    justify-content: center;
    padding: 1rem;
    min-height: 1px;
}

.infinite-scroll-spinner {
    width: 2rem;
    height: 2rem;
    border: 3px solid #e0e0e0;
    border-top-color: #0d6efd;
    border-radius: 50%;
    animation: infinite-scroll-spin 0.8s linear infinite;
}

@keyframes infinite-scroll-spin {
    to { transform: rotate(360deg); }
}

